<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

  html, body {
    width: 100%; height: 100%;
    overflow: hidden;
    font-family: 'Ubuntu', 'Segoe UI', 'Noto Sans', sans-serif;
    background: #1a1a2e;
    color: #e0e0e0;
    user-select: none;
  }

  /* ── Desktop ── */
  #desktop {
    position: fixed;
    top: 0; left: 0; right: 0; bottom: 0;
    background: linear-gradient(135deg, #1a1a2e 0%, #16213e 40%, #0f3460 100%);
    display: flex;
    flex-direction: column;
    justify-content: space-between;
  }

  /* ── Top Bar ── */
  #topbar {
    height: 28px;
    background: #111;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 12px;
    font-size: 13px;
    color: #ddd;
    box-shadow: 0 1px 4px rgba(0,0,0,.5);
    z-index: 100;
  }
  #topbar .left { display: flex; gap: 16px; align-items: center; }
  #topbar .right { display: flex; gap: 14px; align-items: center; }
  #topbar .app-name { font-weight: 600; color: #e95420; }
  #topbar .clock { font-variant-numeric: tabular-nums; }

  /* ── Taskbar / Dock ── */
  #taskbar {
    height: 56px;
    background: rgba(17,17,17,.92);
    backdrop-filter: blur(12px);
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    padding: 0 16px;
    box-shadow: 0 -1px 6px rgba(0,0,0,.4);
    z-index: 100;
  }
  #taskbar button {
    width: 44px; height: 44px;
    border: none; border-radius: 10px;
    background: rgba(255,255,255,.08);
    color: #ccc;
    font-size: 22px;
    cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    transition: background .15s, transform .1s;
    position: relative;
  }
  #taskbar button:hover { background: rgba(255,255,255,.18); transform: scale(1.08); }
  #taskbar button:active { transform: scale(.96); }
  #taskbar button .dot {
    position: absolute; bottom: 2px; left: 50%; transform: translateX(-50%);
    width: 5px; height: 5px; border-radius: 50%;
    background: #e95420;
    opacity: 0;
    transition: opacity .2s;
  }
  #taskbar button.active .dot { opacity: 1; }

  /* ── Window base ── */
  .app-window {
    position: absolute;
    min-width: 360px; min-height: 240px;
    background: #2d2d2d;
    border-radius: 10px;
    box-shadow: 0 8px 32px rgba(0,0,0,.55), 0 0 0 1px rgba(255,255,255,.06);
    display: flex; flex-direction: column;
    overflow: hidden;
    z-index: 200;
  }
  .app-window.hidden { display: none !important; }

  .win-titlebar {
    height: 38px;
    background: #3a3a3a;
    display: flex; align-items: center; justify-content: space-between;
    padding: 0 10px;
    cursor: grab;
    flex-shrink: 0;
    border-bottom: 1px solid #222;
  }
  .win-titlebar:active { cursor: grabbing; }
  .win-title { font-size: 13px; font-weight: 600; color: #ccc; }
  .win-controls { display: flex; gap: 6px; }
  .win-controls button {
    width: 14px; height: 14px; border-radius: 50%; border: none; cursor: pointer;
  }
  .win-close { background: #e95420; }
  .win-close:hover { background: #ff6b35; }
  .win-minimize { background: #f5c542; }
  .win-maximize { background: #44c746; }

  .win-body {
    flex: 1;
    overflow: auto;
    display: flex; flex-direction: column;
  }

  /* ── Files window ── */
  #files-window { width: 680px; height: 460px; }
  #files-toolbar {
    display: flex; align-items: center; gap: 8px;
    padding: 6px 12px;
    background: #333;
    border-bottom: 1px solid #222;
  }
  #files-up {
    width: 30px; height: 30px;
    border: none; border-radius: 6px;
    background: rgba(255,255,255,.1);
    color: #ddd; font-size: 16px;
    cursor: pointer;
    display: flex; align-items: center; justify-content: center;
  }
  #files-up:hover { background: rgba(255,255,255,.2); }
  #files-path {
    flex: 1;
    background: #1e1e1e;
    border: 1px solid #444;
    border-radius: 6px;
    padding: 4px 10px;
    color: #ccc;
    font-size: 13px;
    font-family: 'Ubuntu Mono', 'Fira Code', monospace;
    outline: none;
  }
  #files-path:focus { border-color: #e95420; }
  #files-list {
    flex: 1;
    padding: 8px;
    display: flex;
    flex-wrap: wrap;
    align-content: flex-start;
    gap: 4px;
    overflow-y: auto;
  }
  .fs-item {
    display: flex; flex-direction: column; align-items: center;
    width: 80px; padding: 8px 4px;
    border-radius: 8px;
    cursor: pointer;
    transition: background .12s;
    text-align: center;
  }
  .fs-item:hover { background: rgba(255,255,255,.08); }
  .fs-item .icon { font-size: 32px; margin-bottom: 4px; }
  .fs-item .name { font-size: 11px; color: #ccc; word-break: break-all; }
  .fs-item.folder .icon { color: #e95420; }
  .fs-item.file .icon { color: #7eb8e0; }

  /* ── Notepad window ── */
  #notepad-window { width: 620px; height: 440px; }
  #notepad-toolbar {
    display: flex; align-items: center; gap: 6px;
    padding: 6px 10px;
    background: #333;
    border-bottom: 1px solid #222;
  }
  #new-tab {
    height: 28px; padding: 0 12px;
    border: none; border-radius: 6px;
    background: #e95420;
    color: #fff; font-size: 13px; font-weight: 600;
    cursor: pointer;
    display: flex; align-items: center; justify-content: center;
  }
  #new-tab:hover { background: #ff6b35; }
  #tabs {
    flex: 1;
    display: flex;
    align-items: stretch;
    gap: 2px;
    overflow-x: auto;
    padding: 0 4px;
  }
  .tab {
    height: 28px;
    padding: 0 14px;
    background: #2a2a2a;
    border: none; border-radius: 6px 6px 0 0;
    color: #aaa;
    font-size: 12px;
    cursor: pointer;
    display: flex; align-items: center; gap: 6px;
    white-space: nowrap;
    flex-shrink: 0;
    transition: background .12s, color .12s;
  }
  .tab:hover { background: #333; color: #ddd; }
  .tab.active { background: #2d2d2d; color: #e95420; font-weight: 600; }
  .tab .close-tab {
    width: 14px; height: 14px;
    border: none; border-radius: 50%;
    background: transparent;
    color: #888; font-size: 11px;
    cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    padding: 0;
  }
  .tab .close-tab:hover { background: rgba(255,255,255,.15); color: #fff; }
  #editor {
    flex: 1;
    background: #1e1e1e;
    color: #d4d4d4;
    border: none;
    padding: 12px;
    font-family: 'Ubuntu Mono', 'Fira Code', 'Consolas', monospace;
    font-size: 14px;
    line-height: 1.6;
    resize: none;
    outline: none;
    overflow: auto;
  }
  #editor::placeholder { color: #555; }
</style>
</head>
<body>

<div id="desktop">

  <!-- Top Bar -->
  <div id="topbar">
    <div class="left">
      <span class="app-name">Ubuntu</span>
      <span style="color:#888">|</span>
      <span id="topbar-app-name" style="color:#aaa"></span>
    </div>
    <div class="right">
      <span class="clock" id="clock"></span>
    </div>
  </div>

  <!-- Desktop area (windows rendered here) -->
  <div id="desktop-area" style="flex:1;position:relative;overflow:hidden;">

    <!-- Files Window -->
    <div id="files-window" class="app-window hidden" style="top:60px;left:80px;">
      <div class="win-titlebar" data-drag="files-window">
        <span class="win-title">📁 Files</span>
        <div class="win-controls">
          <button class="win-minimize" title="Minimize"></button>
          <button class="win-maximize" title="Maximize"></button>
          <button class="win-close" title="Close">✕</button>
        </div>
      </div>
      <div class="win-body">
        <div id="files-toolbar">
          <button id="files-up" title="Go up">↑</button>
          <input id="files-path" type="text" readonly>
        </div>
        <div id="files-list"></div>
      </div>
    </div>

    <!-- Notepad Window -->
    <div id="notepad-window" class="app-window hidden" style="top:90px;left:160px;">
      <div class="win-titlebar" data-drag="notepad-window">
        <span class="win-title">📝 Notepad</span>
        <div class="win-controls">
          <button class="win-minimize" title="Minimize"></button>
          <button class="win-maximize" title="Maximize"></button>
          <button class="win-close" title="Close">✕</button>
        </div>
      </div>
      <div class="win-body">
        <div id="notepad-toolbar">
          <button id="new-tab">+ New Tab</button>
          <div id="tabs"></div>
        </div>
        <textarea id="editor" placeholder="Start typing..."></textarea>
      </div>
    </div>

  </div>

  <!-- Taskbar / Dock -->
  <div id="taskbar">
    <button id="open-files" title="Files">
      📁
      <span class="dot"></span>
    </button>
    <button id="open-notepad" title="Notepad">
      📝
      <span class="dot"></span>
    </button>
  </div>

</div>

<script>
(function() {
  "use strict";

  /* ── Clock ── */
  const clockEl = document.getElementById('clock');
  function updateClock() {
    const d = new Date();
    clockEl.textContent = d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }
  updateClock();
  setInterval(updateClock, 30000);

  /* ── Filesystem data ── */
  const filesystem = {
    "/": ["bin", "etc", "home", "usr", "var"],
    "/bin": ["bash", "ls", "cat", "cp", "mv", "rm"],
    "/etc": ["passwd", "hostname", "fstab", "resolv.conf"],
    "/home": ["user"],
    "/home/user": ["Documents", "Downloads", "Pictures", ".bashrc", ".profile"],
    "/home/user/Documents": ["notes.txt", "todo.md", "report.pdf"],
    "/home/user/Downloads": ["setup.deb", "image.png", "archive.tar.gz"],
    "/home/user/Pictures": ["wallpaper.jpg", "screenshot.png", "photo.jpg"],
    "/usr": ["bin", "lib", "share", "local"],
    "/usr/bin": ["python3", "gcc", "make", "git"],
    "/usr/lib": ["libc.so", "libm.so", "libdl.so"],
    "/usr/share": ["doc", "man", "locale"],
    "/var": ["log", "tmp", "cache"],
    "/var/log": ["syslog", "auth.log", "kern.log"],
    "/var/tmp": [],
    "/var/cache": ["apt", "pip"]
  };

  function isFolder(path) {
    return filesystem[path] !== undefined;
  }

  function getEntries(path) {
    return filesystem[path] || [];
  }

  function getIcon(name) {
    if (isFolder(pathFor(name))) return '📁';
    const ext = name.split('.').pop().toLowerCase();
    const icons = {
      txt: '📄', md: '📄', pdf: '📕', jpg: '🖼️', jpeg: '🖼️',
      png: '🖼️', gif: '🖼️', deb: '📦', tar: '📦', gz: '📦',
      sh: '⚙️', conf: '⚙️', log: '📋', json: '📋', xml: '📋',
      html: '🌐', css: '🎨', js: '📜', py: '🐍', c: '📜', h: '📜',
      o: '⚙️', so: '⚙️', doc: '📕', xls: '📊', ppt: '📊'
    };
    return icons[ext] || '📄';
  }

  /* ── Files app state ── */
  let currentPath = "/";

  function renderFiles() {
    const list = document.getElementById('files-list');
    const pathInput = document.getElementById('files-path');
    pathInput.value = currentPath;
    list.innerHTML = '';

    const entries = getEntries(currentPath);
    // Sort: folders first, then files
    const sorted = entries.sort((a, b) => {
      const aFold = isFolder(pathFor(a)) ? 0 : 1;
      const bFold = isFolder(pathFor(b)) ? 0 : 1;
      if (aFold !== bFold) return aFold - bFold;
      return a.localeCompare(b);
    });

    sorted.forEach(name => {
      const item = document.createElement('div');
      const fullPath = pathFor(name);
      const folder = isFolder(fullPath);
      item.className = 'fs-item ' + (folder ? 'folder' : 'file');
      item.innerHTML = '<span class="icon">' + getIcon(name) + '</span><span class="name">' + name + '</span>';

      if (folder) {
        item.addEventListener('dblclick', function() {
          currentPath = fullPath;
          renderFiles();
        });
      }
      list.appendChild(item);
    });
  }

  function pathFor(name) {
    if (currentPath === '/') return '/' + name;
    return currentPath + '/' + name;
  }

  document.getElementById('files-up').addEventListener('click', function() {
    if (currentPath !== '/') {
      currentPath = currentPath.substring(0, currentPath.lastIndexOf('/')) || '/';
      renderFiles();
    }
  });

  /* ── Notepad app state ── */
  const STORAGE_KEY = 'ubuntu-notepad-tabs';

  function loadTabs() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) return JSON.parse(raw);
    } catch(e) {}
    return [];
  }

  function saveTabs() {
    const tabs = getTabsData();
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tabs));
  }

  let tabs = [];
  let activeTabId = null;
  let tabCounter = 0;

  function getTabsData() {
    return tabs.map(t => ({ id: t.id, name: t.name, content: document.getElementById('editor-' + t.id)?.value || '' }));
  }

  function initNotepad() {
    const loaded = loadTabs();
    if (loaded.length > 0) {
      tabs = loaded;
      tabCounter = Math.max(...tabs.map(t => t.id), 0);
      // Restore content
      tabs.forEach(t => {
        const editor = document.getElementById('editor-' + t.id);
        if (editor) editor.value = t.content;
      });
      // Activate last tab or first
      activeTabId = tabs[tabs.length - 1].id;
    } else {
      // Start with one tab
      activeTabId = ++tabCounter;
      tabs.push({ id: activeTabId, name: 'Untitled', content: '' });
    }
    renderTabs();
    switchTab(activeTabId);
  }

  function renderTabs() {
    const tabsContainer = document.getElementById('tabs');
    tabsContainer.innerHTML = '';
    tabs.forEach(t => {
      const tabEl = document.createElement('button');
      tabEl.className = 'tab' + (t.id === activeTabId ? ' active' : '');
      tabEl.innerHTML = '<span>' + t.name + '</span><button class="close-tab" data-tab-id="' + t.id + '">✕</button>';
      tabEl.addEventListener('click', function(e) {
        if (e.target.classList.contains('close-tab')) {
          closeTab(t.id);
          e.stopPropagation();
        } else {
          switchTab(t.id);
        }
      });
      tabsContainer.appendChild(tabEl);
    });
  }

  function switchTab(id) {
    // Save current content
    const currentEditor = document.getElementById('editor-' + activeTabId);
    if (currentEditor) {
      const tab = tabs.find(t => t.id === activeTabId);
      if (tab) tab.content = currentEditor.value;
    }

    activeTabId = id;
    const editor = document.getElementById('editor-' + activeTabId);
    if (editor) {
      editor.style.display = 'block';
      editor.focus();
    }
    renderTabs();
    saveTabs();
  }

  function closeTab(id) {
    const idx = tabs.findIndex(t => t.id === id);
    if (idx === -1) return;
    tabs.splice(idx, 1);

    // Remove editor
    const editor = document.getElementById('editor-' + id);
    if (editor) editor.style.display = 'none';

    if (tabs.length === 0) {
      // Create a new tab
      activeTabId = ++tabCounter;
      tabs.push({ id: activeTabId, name: 'Untitled', content: '' });
      const newEditor = document.createElement('textarea');
      newEditor.id = 'editor-' + activeTabId;
      newEditor.style.display = 'none';
      newEditor.placeholder = 'Start typing...';
      document.getElementById('editor').style.display = 'none';
      document.getElementById('editor').id = 'editor-' + activeTabId;
      newEditor.id = 'editor-' + activeTabId;
      document.querySelector('#notepad-window .win-body').appendChild(newEditor);
      switchTab(activeTabId);
    } else if (activeTabId === id) {
      const newActive = tabs[Math.min(idx, tabs.length - 1)];
      switchTab(newActive.id);
    }
    renderTabs();
    saveTabs();
  }

  document.getElementById('new-tab').addEventListener('click', function() {
    // Save current
    const currentEditor = document.getElementById('editor-' + activeTabId);
    if (currentEditor) {
      const tab = tabs.find(t => t.id === activeTabId);
      if (tab) tab.content = currentEditor.value;
    }

    activeTabId = ++tabCounter;
    const name = 'Untitled ' + activeTabId;
    tabs.push({ id: activeTabId, name: name, content: '' });

    // Create new textarea
    const newEditor = document.createElement('textarea');
    newEditor.id = 'editor-' + activeTabId;
    newEditor.style.display = 'none';
    newEditor.placeholder = 'Start typing...';
    document.querySelector('#notepad-window .win-body').appendChild(newEditor);

    // Hide old editor
    const oldEditor = document.getElementById('editor-' + (activeTabId - 1));
    if (oldEditor) oldEditor.style.display = 'none';

    switchTab(activeTabId);
    renderTabs();
    saveTabs();
  });

  // Save on input
  document.getElementById('editor').addEventListener('input', function() {
    const tab = tabs.find(t => t.id === activeTabId);
    if (tab) tab.content = this.value;
    saveTabs();
  });

  /* ── Window management ── */
  const filesWindow = document.getElementById('files-window');
  const notepadWindow = document.getElementById('notepad-window');
  const openFilesBtn = document.getElementById('open-files');
  const openNotepadBtn = document.getElementById('open-notepad');
  const topbarAppName = document.getElementById('topbar-app-name');

  let filesVisible = false;
  let notepadVisible = false;

  function showWindow(win, btn, appName) {
    win.classList.remove('hidden');
    btn.classList.add('active');
    topbarAppName.textContent = appName;
    if (appName === 'Files') renderFiles();
    if (appName === 'Notepad') {
      // Ensure editor exists
      const editor = document.getElementById('editor-' + activeTabId);
      if (editor) editor.style.display = 'block';
    }
  }

  function hideWindow(win, btn, appName) {
    win.classList.add('hidden');
    btn.classList.remove('active');
    topbarAppName.textContent = '';
  }

  openFilesBtn.addEventListener('click', function() {
    if (filesVisible) {
      hideWindow(filesWindow, openFilesBtn, 'Files');
      filesVisible = false;
    } else {
      showWindow(filesWindow, openFilesBtn, 'Files');
      filesVisible = true;
    }
  });

  openNotepadBtn.addEventListener('click', function() {
    if (notepadVisible) {
      hideWindow(notepadWindow, openNotepadBtn, 'Notepad');
      notepadVisible = false;
    } else {
      showWindow(notepadWindow, openNotepadBtn, 'Notepad');
      notepadVisible = true;
    }
  });

  // Close buttons
  filesWindow.querySelector('.win-close').addEventListener('click', function() {
    hideWindow(filesWindow, openFilesBtn, 'Files');
    filesVisible = false;
  });

  notepadWindow.querySelector('.win-close').addEventListener('click', function() {
    hideWindow(notepadWindow, openNotepadBtn, 'Notepad');
    notepadVisible = false;
  });

  /* ── Draggable windows ── */
  document.querySelectorAll('.win-titlebar[data-drag]').forEach(titlebar => {
    const winId = titlebar.getAttribute('data-drag');
    const win = document.getElementById(winId);
    let isDragging = false, startX, startY, origLeft, origTop;

    titlebar.addEventListener('mousedown', function(e) {
      if (e.target.classList.contains('win-close') || e.target.classList.contains('win-minimize') || e.target.classList.contains('win-maximize')) return;
      isDragging = true;
      startX = e.clientX;
      startY = e.clientY;
      origLeft = win.offsetLeft;
      origTop = win.offsetTop;
      win.style.zIndex = 300;
      e.preventDefault();
    });

    document.addEventListener('mousemove', function(e) {
      if (!isDragging) return;
      const dx = e.clientX - startX;
      const dy = e.clientY - startY;
      win.style.left = (origLeft + dx) + 'px';
      win.style.top = (origTop + dy) + 'px';
    });

    document.addEventListener('mouseup', function() {
      isDragging = false;
    });
  });

  /* ── Init ── */
  renderFiles();
  initNotepad();

})();
</script>
</body>
</html>
